#define BUCKET_WARP_LOG_SIZE	5
#define BUCKET_WARP_N			1

#ifdef BUCKET_WG_SIZE_1
#define BUCKET_THREAD_N BUCKET_WG_SIZE_1
#else
#define BUCKET_THREAD_N			(BUCKET_WARP_N << BUCKET_WARP_LOG_SIZE)
#endif
#define BUCKET_BLOCK_MEMORY		(DIVISIONS * BUCKET_WARP_N)
#define BUCKET_BAND				128
#define LOG_DIVISIONS 10
#define DIVISIONS (1 << LOG_DIVISIONS)

#pragma OPENCL EXTENSION cl_khr_int64 : enable

__device__ int addOffset(volatile unsigned int *s_offset, unsigned int data, unsigned int threadTag){
    unsigned int count;

    do{
        count = s_offset[data] & 0x07FFFFFFU;
        count = threadTag | (count + 1);
        s_offset[data] = count;
    }while(s_offset[data] != count);

	return (count & 0x07FFFFFFU) - 1;
}

__kernel void
bucketcount( read_only image1d_float input, write_only image1d_int indice, write_only image1d_uint d_prefixoffsets, int size, read_only image1d_float texPivot)
{
	volatile __local unsigned int s_offset[BUCKET_BLOCK_MEMORY]; 

    const unsigned int threadTag = get_local_id(0) << (32 - BUCKET_WARP_LOG_SIZE);
    const int warpBase = (get_local_id(0) >> BUCKET_WARP_LOG_SIZE) * DIVISIONS; 
    const int numThreads = get_global_size(0);
	for (int i = get_local_id(0); i < BUCKET_BLOCK_MEMORY; i += get_local_size(0))
		s_offset[i] = 0; 

	barrier(CLK_LOCAL_MEM_FENCE); 

	for (int tid = get_global_id(0); tid < size; tid += numThreads) {
		float elem = read_imagef(input, tid).x; 

		int idx  = DIVISIONS/2 - 1; 
		int jump = DIVISIONS/4; 
		float piv = read_imagef(texPivot, idx).x; 

		while(jump >= 1){
			idx = (elem < piv) ? (idx - jump) : (idx + jump);
			piv = read_imagef(texPivot, idx).x; 
			jump /= 2; 
		}
		idx = (elem < piv) ? idx : (idx + 1); 

		int indice_val = (addOffset(s_offset + warpBase, idx, threadTag) << LOG_DIVISIONS) + idx;
		write_imagef(indice, tid, (int4){indice_val, 0, 0, 0});
	}

	barrier(CLK_LOCAL_MEM_FENCE); 

	int prefixBase = get_group_id(0) * BUCKET_BLOCK_MEMORY; 

	for (int i = get_local_id(0); i < BUCKET_BLOCK_MEMORY; i += get_local_size(0))
		write_imageui(d_prefixoffsets, prefixBase + i, (uint4){s_offset[i] & 0x07FFFFFFU, 0, 0, 0});
}

__kernel void bucketprefixoffset(read_only image1d_uint d_prefixoffsets, write_only image1d_uint d_offsets, int blocks) {
	int tid = get_global_id(0); 
	int size = blocks * BUCKET_BLOCK_MEMORY; 
	int sum = 0; 

	for (int i = tid; i < size; i += DIVISIONS) {
		uint4 x = read_imageui(d_prefixoffsets, i);
		write_imageui(d_prefixoffsets, i, (uint4){sum, 0, 0, 0});
		sum += x.x; 
	}

	write_imageui(d_offsets, tid, (uint4){sum, 0, 0, 0});
}

__kernel void
bucketsort(read_only image1d_float input, read_only image1d_int indice, write_only image1d_float output, int size, read_only image1d_uint d_prefixoffsets, 
		   read_only image1d_uint l_offsets)
{
	volatile __local unsigned int s_offset[BUCKET_BLOCK_MEMORY]; 

	int prefixBase = get_group_id(0) * BUCKET_BLOCK_MEMORY; 
    const int warpBase = (get_local_id(0) >> BUCKET_WARP_LOG_SIZE) * DIVISIONS; 
    const int numThreads = get_global_size(0);
	for (int i = get_local_id(0); i < BUCKET_BLOCK_MEMORY; i += get_local_size(0))
		s_offset[i] = read_imageui(l_offsets, i & (DIVISIONS - 1)).x + read_imageui(d_prefixoffsets, prefixBase + i).x; 

	barrier(CLK_LOCAL_MEM_FENCE); 

	for (int tid = get_global_id(0); tid < size; tid += numThreads) {

		float elem = read_imagef(input, tid).x; 
		int4 id = read_imagei(indice, tid);
		int id_val = id.x;

		int out_idx = s_offset[warpBase + (id_val & (DIVISIONS - 1))] + (id_val >> LOG_DIVISIONS);
		write_imagef(output, out_idx, (float4){elem, 0, 0, 0});
	}
}

