#define DIVISIONS 1024

#pragma OPENCL EXTENSION cl_khr_int64 : enable

__constant int constStartAddr[DIVISIONS + 1]; 
__constant int finalStartAddr[DIVISIONS + 1]; 
__constant int nullElems[DIVISIONS]; 

__device__ float4 sortElem(float4 r) {
	float4 nr;

	nr.x = (r.x > r.y) ? r.y : r.x; 
	nr.y = (r.y > r.x) ? r.y : r.x; 
	nr.z = (r.z > r.w) ? r.w : r.z; 
	nr.w = (r.w > r.z) ? r.w : r.z; 

	r.x = (nr.x > nr.z) ? nr.z : nr.x; 
	r.y = (nr.y > nr.w) ? nr.w : nr.y; 
	r.z = (nr.z > nr.x) ? nr.z : nr.x; 
	r.w = (nr.w > nr.y) ? nr.w : nr.y; 

	nr.x = r.x; 
	nr.y = (r.y > r.z) ? r.z : r.y; 
	nr.z = (r.z > r.y) ? r.z : r.y; 
	nr.w = r.w; 
	return nr; 
}

__device__ float4 getLowest(float4 a, float4 b)
{

	a.x = (a.x < b.w) ? a.x : b.w; 
	a.y = (a.y < b.z) ? a.y : b.z; 
	a.z = (a.z < b.y) ? a.z : b.y; 
	a.w = (a.w < b.x) ? a.w : b.x; 
	return a; 
}

__device__ float4 getHighest(float4 a, float4 b)
{
	b.x = (a.w >= b.x) ? a.w : b.x; 
	b.y = (a.z >= b.y) ? a.z : b.y; 
	b.z = (a.y >= b.z) ? a.y : b.z; 
	b.w = (a.x >= b.w) ? a.x : b.w; 
	return b; 
}


__kernel void
mergeSortFirst(write_only image1d_float4 result, int listsize, read_only image1d_float4 tex) 
{

    int bx = get_group_id(0);


		if(bx*get_local_size(0) + get_local_id(0) < listsize/4){
			float4 r = read_imagef(tex, (int)(bx*get_local_size(0) + get_local_id(0)));
			write_imagef(result, bx * get_local_size(0) + get_local_id(0), sortElem(r)); 
		}
}

__kernel void
mergeSortPass(write_only image1d_float4 result, int nrElems, int threadsPerDiv, read_only image1d_float4 tex) 
{
	int tid = (get_group_id(0) * get_local_size(0)) + get_local_id(0); 

	int division = tid / threadsPerDiv; 
	if(division >= DIVISIONS) return; 

	int int_tid = tid - division * threadsPerDiv; 
	int Astart = constStartAddr[division] + int_tid * nrElems; 

	int Bstart = Astart + nrElems/2;

	if(Astart >= constStartAddr[division + 1]) 
		return; 
	if(Bstart >= constStartAddr[division + 1]){
		for(int i=0; i<(constStartAddr[division + 1] - Astart); i++)
		{
			write_imagef(result, Astart + i, read_imagef(tex, Astart + i)); 
		}
		return; 
	}

	int aidx = 0; 
	int bidx = 0; 
	int outidx = 0; 
	float4 a, b;
	a = read_imagef(tex, Astart + aidx);  
	b = read_imagef(tex, Bstart + bidx); 

	while(true)
	{

		float4 nextA = read_imagef(tex, Astart + aidx + 1); 
		float4 nextB = read_imagef(tex, Bstart + bidx + 1); 

		float4 na = getLowest(a,b); 
		float4 nb = getHighest(a,b); 
		a = sortElem(na); 
		b = sortElem(nb); 

		write_imagef(result, Astart + outidx, a);
		outidx++;

		bool elemsLeftInA; 
		bool elemsLeftInB;

		elemsLeftInA = (aidx + 1 < nrElems/2); 
		elemsLeftInB = (bidx + 1 < nrElems/2) && (Bstart + bidx + 1 < constStartAddr[division + 1]); 

		if(elemsLeftInA){
			if(elemsLeftInB){
				if(nextA.x < nextB.x) { aidx += 1; a = nextA; }  
				else { bidx += 1;  a = nextB; }
			}
			else {
				aidx += 1; a = nextA;
			}
		}
		else {
			if(elemsLeftInB){
				bidx += 1;  a = nextB;
			}
			else {
				break; 
			}
		}

	}
	write_imagef(result, Astart + outidx, b);
}

__kernel void
mergepack(read_only image1d_float orig, write_only image1d_float result) 
{
	int idx = get_global_id(0); 
	int division = get_group_id(1); 

	if((finalStartAddr[division] + idx) >= finalStartAddr[division + 1]) return; 
	float val = read_imagef(orig, constStartAddr[division]*4 + nullElems[division] + idx);
	write_imagef(result, finalStartAddr[division] + idx, (float4){val, 0, 0, 0});
}
